  "inlineSchema": "// Prisma Schema for Paul - Uprising Studio Pipeline\n// Postgres database for managing clients, projects, invoices, and activities\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── Clients ────────────────────────────────────────────────\n\nmodel Client {\n  id      String       @id @default(cuid())\n  name    String\n  email   String?\n  phone   String?\n  company String?\n  website String?\n  source  String? // ex: \"referral\", \"cold-outreach\", \"website\"\n  status  ClientStatus @default(LEAD)\n  score   Int          @default(0) // Lead scoring (0-100)\n  notes   String?\n  tags    String[] // ex: [\"construction\", \"renovation\", \"quebec\"]\n\n  // Social profiles (enrichment)\n  linkedinUrl  String?\n  facebookUrl  String?\n  instagramUrl String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  projects   Project[]\n  invoices   Invoice[]\n  activities Activity[]\n\n  @@map(\"clients\")\n}\n\nenum ClientStatus {\n  LEAD\n  PROSPECT\n  QUALIFIED\n  PROPOSAL\n  NEGOTIATION\n  WON\n  LOST\n  CHURNED\n}\n\n// ─── Projects ───────────────────────────────────────────────\n\nmodel Project {\n  id          String        @id @default(cuid())\n  name        String\n  description String?\n  status      ProjectStatus @default(PENDING)\n  budget      Float?\n  currency    String        @default(\"CAD\")\n  startDate   DateTime?\n  endDate     DateTime?\n  deadline    DateTime?\n\n  clientId String\n  client   Client @relation(fields: [clientId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  invoices   Invoice[]\n  activities Activity[]\n\n  @@map(\"projects\")\n}\n\nenum ProjectStatus {\n  PENDING\n  IN_PROGRESS\n  ON_HOLD\n  COMPLETED\n  CANCELLED\n}\n\n// ─── Invoices ───────────────────────────────────────────────\n\nmodel Invoice {\n  id          String        @id @default(cuid())\n  number      String        @unique\n  amount      Float\n  currency    String        @default(\"CAD\")\n  tax         Float         @default(0)\n  total       Float\n  status      InvoiceStatus @default(DRAFT)\n  dueDate     DateTime?\n  paidAt      DateTime?\n  description String?\n\n  clientId String\n  client   Client @relation(fields: [clientId], references: [id], onDelete: Cascade)\n\n  projectId String?\n  project   Project? @relation(fields: [projectId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"invoices\")\n}\n\nenum InvoiceStatus {\n  DRAFT\n  SENT\n  PAID\n  OVERDUE\n  CANCELLED\n}\n\n// ─── Activities / Timeline ──────────────────────────────────\n\nmodel Activity {\n  id          String       @id @default(cuid())\n  type        ActivityType\n  title       String\n  description String?\n  metadata    Json? // flexible JSON for extra data\n\n  clientId String?\n  client   Client? @relation(fields: [clientId], references: [id], onDelete: Cascade)\n\n  projectId String?\n  project   Project? @relation(fields: [projectId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n\n  @@map(\"activities\")\n}\n\nenum ActivityType {\n  NOTE\n  EMAIL\n  CALL\n  MEETING\n  TASK\n  STATUS_CHANGE\n  AI_BRIEFING\n  AI_REPORT\n}\n\n// ─── Briefings & Reports ────────────────────────────────────\n\nmodel Briefing {\n  id      String       @id @default(cuid())\n  type    BriefingType\n  title   String\n  content String // Markdown content\n  sentVia String[] // ex: [\"discord\", \"email\"]\n  sentAt  DateTime?\n\n  createdAt DateTime @default(now())\n\n  @@map(\"briefings\")\n}\n\nenum BriefingType {\n  DAILY\n  WEEKLY\n  CUSTOM\n}\n\n// ─── AI Conversations (Ollama interactions log) ─────────────\n\nmodel AiConversation {\n  id         String  @id @default(cuid())\n  model      String // ex: \"kimi-k2.5\", \"glm-5\"\n  prompt     String\n  response   String\n  tokensUsed Int?\n  durationMs Int?\n  context    String? // ex: \"client-enrichment\", \"email-draft\", \"briefing\"\n\n  createdAt DateTime @default(now())\n\n  @@map(\"ai_conversations\")\n}\n",
